import { useLayoutEffect, useState } from "react";
import styles from "./TutorialCoachmark.module.css";

// top 배치: 카드 좌측 모서리에서 꼬리(=앵커)까지의 거리(px)
const TAIL_OFFSET_X = 24;
// right 배치: 카드 상단 모서리에서 꼬리(=앵커)까지의 거리(px)
const TAIL_OFFSET_Y = 44;

/**
 * 기능을 소개하는 튜토리얼 코치마크.
 * anchorRef 가 가리키는 요소 옆/위에 떠서 꼬리로 해당 요소를 가리킨다.
 *
 * placement: "top"  → 앵커 위쪽, 꼬리는 아래로 (예: 파일 첨부 버튼)
 *            "right" → 앵커 오른쪽, 꼬리는 왼쪽으로 (예: 레퍼런스 카드 ... 메뉴)
 * variant:   "image" → 이미지 첨부 일러스트
 *            "reaction" → 레퍼런스 반응 메뉴 일러스트
 */
const TutorialCoachmark = ({
  anchorRef,
  onClose,
  title = "이미지를 첨부해 가이드를 요청해보세요",
  description = "어떤 부분에서 막혔는지 이미지를 같이 첨부해주세요. 보다 정교한 가이드를 받아볼 수 있어요.",
  step,
  variant = "image",
  placement = "top",
  gap = 12,
}) => {
  const [pos, setPos] = useState(null);

  useLayoutEffect(() => {
    const update = () => {
      const el = anchorRef?.current;
      if (!el) return;
      const r = el.getBoundingClientRect();
      if (placement === "right") {
        setPos({
          left: r.right + gap, // 아이콘 오른쪽 gap 만큼 여백
          top: r.top + r.height / 2 - TAIL_OFFSET_Y, // 꼬리가 아이콘 중앙에 오도록
        });
      } else {
        setPos({
          left: r.left + r.width / 2 - TAIL_OFFSET_X, // 꼬리가 아이콘 중앙에 오도록
          bottom: window.innerHeight - r.top + gap, // 아이콘 위 gap 만큼 여백
        });
      }
    };
    update();
    window.addEventListener("resize", update);
    window.addEventListener("scroll", update, true); // 보드 내부 스크롤도 추적
    return () => {
      window.removeEventListener("resize", update);
      window.removeEventListener("scroll", update, true);
    };
  }, [anchorRef, placement, gap]);

  if (!pos) return null;

  const isRight = placement === "right";
  const cardStyle = isRight
    ? { left: pos.left, top: pos.top }
    : { left: pos.left, bottom: pos.bottom };

  return (
    <div className={styles.overlay}>
      <div
        className={styles.card}
        role="dialog"
        aria-modal="true"
        style={cardStyle}
      >
        <h3 className={styles.title}>{title}</h3>
        <p className={styles.description}>{description}</p>

        {variant === "reaction" ? <ReactionMock /> : <ImageMock />}

        <div className={styles.footer}>
          {step && <span className={styles.step}>{step}</span>}
          <button type="button" className={styles.startBtn} onClick={onClose}>
            시작하기
          </button>
        </div>

        {/* 앵커를 가리키는 꼬리 */}
        {isRight ? (
          <span
            className={styles.tailLeft}
            style={{ top: TAIL_OFFSET_Y }}
            aria-hidden="true"
          />
        ) : (
          <span
            className={styles.tail}
            style={{ left: TAIL_OFFSET_X }}
            aria-hidden="true"
          />
        )}
      </div>
    </div>
  );
};

/* 이미지 첨부 일러스트 */
const ImageMock = () => (
  <div className={styles.imageBox}>
    <ImagePlaceholderIcon />
  </div>
);

